styles WorkWithPlusTheme
{
	.GridRow
	{
		border-style: none;
		border-width: 0px;
	}
	.WorkWithRowSelected
	{
		@include GridRow;
		background-color: #add6bb;
		border-bottom: 1px;
		border-left: 0;
		border-right: 0;
		border-top: 1px;
		border-bottom-color: $colors.GridActionColor;
		border-top-color: $colors.GridActionColor;
		border-style: solid;
	}
	.WorkWithRowHover
	{
		@include GridRow;
		background-color: #cfd;
		border-bottom: 1px;
		border-top: 1px;
		border-bottom-color: $colors.GridActionColor;
		border-top-color: $colors.GridActionColor;
		border-style: solid;
	}
	.WorkWithHeader
	{
		@include GridRow;
		background-color: $colors.PaginationBarDefaultBackgroundColor;
		border-bottom: 1px solid;
		border-left: 0;
		border-right: 0;
		padding-bottom: 3px;
		padding-left: 3px;
		padding-right: 0px;
		padding-top: 3px;
		border-bottom-color: $colors.GridLineColor;
		height: 38px;
		vertical-align: middle;
	}
	.GridWithBorderColorHeader
	{
		@include GridRow;
		border-bottom: 3px;
		border-left: 0;
		border-right: 0;
		border-top: 0;
		color: $colors.AttributeForecolor;
		border-bottom-color: $colors.BaseColor;
		border-style: solid;
	}
	.GridNoBorderHeader
	{
		@include GridRow;
		background-color: $colors.DataBackgroundColor;
	}
	.TabPage
	{
		border-style: none;
		border-width: 0px;
	}
	.EmbeddedPage
	{
		border-style: none;
		border-width: 0px;
	}
	.Animation
	{
		gx-animation-type: idNative;
	}
	.TableRow
	{
		border-style: none;
		border-width: 0px;
	}
	.TableCell
	{
		border-style: none;
		border-width: 0px;
	}
	.Popup
	{
		border-style: none;
		border-width: 0px;
	}
	.PopupLight
	{
		@include Popup;
		min-height: 550px;
	}
	.CallTarget
	{
		border-style: none;
		border-width: 0px;
	}
	.NavigationStyle
	{
		gx-nav-style-mode: idNavStyleModeStatic;
		gx-nav-style-top-target-height: 15vh;
		gx-nav-style-right-target-width: 400px;
		gx-nav-style-bottom-target-height: 10vh;
		gx-nav-style-left-target-width: 400px;
		gx-nav-style-top-target-height-collapsed: 10vw;
		gx-nav-style-right-target-width-collapsed: 20vw;
		gx-nav-style-bottom-target-height-collapsed: 10vh;
		gx-nav-style-left-target-width-collapsed: 20vw;
	}
	.ActionGroupItem
	{
		border-style: none;
		border-width: 0px;
	}
	.QueryViewer
	{
		gx-qv-pivot-table-footer-rows-per-page: True;
		gx-qv-table-footer-rows-per-page: True;
	}
	.Switch
	{
		gx-switch-on-background-color: #5cb85c;
		gx-switch-on-text-color: #fff;
		gx-switch-off-background-color: #eee;
		gx-switch-off-text-color: #000;
	}
	.Rating
	{
		gx-selected-color: #f5c145;
		gx-unselected-color: #e6e6e6;
		gx-label-class: Label;
		border-style: none;
		border-width: 0px;
